{
  "integrative": {
    "title": "Integrative Close: Analyzing System Performance",
    "objective": "Synthesize the selection of instruments for power and energy while explaining the functional difference between instantaneous and cumulative measurement.",
    "retrievalTextLines": [
      "To provide a complete picture of an electrical system, we often need to look at both the immediate performance and the long-term usage. A Wattmeter gives us a 'snapshot' of the power being used at that exact second.",
      "However, to understand the impact on a customer's bill or the total work done over a day, we must look at the energy consumed over time. Selecting the right tool depends on whether you are measuring a rate or a total."
    ],
    "questionText": "You are investigating a high electricity bill for a commercial kitchen. Explain which specific instrument you would use to measure the instantaneous power of a large oven, which instrument you would use to record its total usage over a full shift, and why the Energy Meter is the only appropriate choice for the latter.",
    "answerGuidance": [
      "Wattmeter for instantaneous power",
      "Energy Meter (or kWh meter) for total usage",
      "The Energy Meter records consumption over time (accumulates data), whereas a Wattmeter only shows the rate of work at a single moment."
    ],
    "hint": "Think about the difference between the 'speed' of electricity use right now versus the 'distance' covered over several hours."
  }
}

